        "fieldViolations": [
          {
            "field": "trigger.repository_event_config.repository_type",
            "description": "Invalid value at 'trigger.repository_event_config.repository_type' (type.googleapis.com/google.devtools.cloudbuild.v1.RepositoryEventConfig.RepositoryType), \"GITLAB\""
          },
